import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

export default function Login() {
  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [error, setError]       = useState('');
  const [loading, setLoading]   = useState(false);
  const [showPass, setShowPass] = useState(false);
  const { login } = useAuth();
  const navigate  = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      await login(email, password);
      navigate('/dashboard');
    } catch (e: any) {
      setError(e.response?.data?.message || 'Invalid email or password');
    } finally { setLoading(false); }
  };

  return (
    <div style={{ minHeight:'100vh', width:'100%', position:'relative', display:'flex', alignItems:'center', justifyContent:'center', fontFamily:"'DM Sans', sans-serif", overflow:'hidden' }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@600;700&family=DM+Sans:wght@400;500;600;700&display=swap');
        * { box-sizing:border-box; }
        .li:focus { border-color:#818cf8 !important; box-shadow:0 0 0 3px rgba(129,140,248,0.25) !important; outline:none; }
        .li::placeholder { color:rgba(255,255,255,0.22) !important; }
        .lbtn:hover:not(:disabled) { transform:translateY(-2px); box-shadow:0 14px 36px rgba(99,102,241,0.55) !important; filter:brightness(1.08); }
        .lbtn:active:not(:disabled) { transform:translateY(0); }
        .lbtn:disabled { opacity:.65; cursor:not-allowed; }
        .card-up { animation:cUp .65s cubic-bezier(.16,1,.3,1) forwards; }
        @keyframes cUp { from{opacity:0;transform:translateY(32px)} to{opacity:1;transform:translateY(0)} }
        @keyframes loginBgZoom { 0%,100%{transform:scale(1)} 50%{transform:scale(1.1)} }
        .login-bg { animation: loginBgZoom 30s ease-in-out infinite; will-change: transform; }
        .eye-btn:hover { color:rgba(255,255,255,0.9) !important; }
        a.rlink:hover { opacity:.75; }
        @keyframes shimmer { 0%{background-position:-200% 0} 100%{background-position:200% 0} }
        .rainbow-line {
          height:3px; border-radius:99px; margin:0 auto 32px;
          background:linear-gradient(90deg,#6366f1,#8b5cf6,#ec4899,#f43f5e,#f59e0b,#10b981,#0ea5e9,#6366f1);
          background-size:200% 100%;
          animation:shimmer 4s linear infinite;
        }
      `}</style>

      {/* Background image */}
      <div className="login-bg" style={{ position:'absolute', inset:0, zIndex:0, backgroundImage:'url(/library-bg.jpg)', backgroundSize:'cover', backgroundPosition:'center', filter:'brightness(0.35)' }} />
      {/* Color overlay */}
      <div style={{ position:'absolute', inset:0, zIndex:1, background:'linear-gradient(135deg, rgba(30,27,75,0.75) 0%, rgba(76,29,149,0.5) 50%, rgba(15,23,42,0.7) 100%)' }} />
      {/* Vignette */}
      <div style={{ position:'absolute', inset:0, zIndex:1, background:'radial-gradient(ellipse at center, transparent 20%, rgba(0,0,0,0.6) 100%)' }} />

      {/* Floating blobs */}
      <div style={{ position:'absolute', top:'10%', left:'8%', width:320, height:320, borderRadius:'50%', background:'radial-gradient(circle, rgba(99,102,241,0.18) 0%, transparent 70%)', zIndex:1, pointerEvents:'none' }} />
      <div style={{ position:'absolute', bottom:'12%', right:'6%', width:280, height:280, borderRadius:'50%', background:'radial-gradient(circle, rgba(139,92,246,0.15) 0%, transparent 70%)', zIndex:1, pointerEvents:'none' }} />
      <div style={{ position:'absolute', top:'45%', right:'20%', width:180, height:180, borderRadius:'50%', background:'radial-gradient(circle, rgba(236,72,153,0.1) 0%, transparent 70%)', zIndex:1, pointerEvents:'none' }} />

      {/* Content */}
      <div className="card-up" style={{ position:'relative', zIndex:2, width:'100%', maxWidth:460, margin:'0 20px', display:'flex', flexDirection:'column', alignItems:'center' }}>

        {/* University */}
        <p style={{ fontSize:11.5, fontWeight:600, letterSpacing:'2px', color:'rgba(165,180,252,0.6)', textTransform:'uppercase', marginBottom:10, textAlign:'center' }}>
          Bangladesh Army University of Science and Technology
        </p>

        {/* Title */}
        <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:52, fontWeight:700, color:'#ffffff', margin:'0 0 12px', textAlign:'center', letterSpacing:'-1.5px', lineHeight:1, textShadow:'0 2px 20px rgba(99,102,241,0.4)' }}>
          LibraryMS
        </h1>

        {/* Rainbow shimmer line */}
        <div className="rainbow-line" style={{ width:70, marginBottom:32 }} />

        {/* Glass Card */}
        <div style={{
          width:'100%',
          background:'rgba(10,9,26,0.72)',
          backdropFilter:'blur(32px)',
          WebkitBackdropFilter:'blur(32px)',
          border:'1px solid rgba(129,140,248,0.2)',
          borderRadius:24,
          padding:'40px 38px 34px',
          boxShadow:'0 32px 80px rgba(0,0,0,0.55), 0 0 0 1px rgba(99,102,241,0.1), inset 0 1px 0 rgba(255,255,255,0.06)',
          position:'relative', overflow:'hidden',
        }}>
          {/* Card top accent line */}
          <div style={{ position:'absolute', top:0, left:0, right:0, height:3, background:'linear-gradient(90deg,#6366f1,#8b5cf6,#ec4899)', borderRadius:'24px 24px 0 0' }} />

          <h2 style={{ fontSize:26, fontWeight:700, color:'#ffffff', margin:'4px 0 6px', textAlign:'center', letterSpacing:'-0.3px' }}>Welcome back</h2>
          <p style={{ fontSize:14, color:'rgba(165,180,252,0.5)', margin:'0 0 28px', textAlign:'center' }}>Sign in to access your library account</p>

          {error && (
            <div style={{ background:'rgba(244,63,94,0.12)', border:'1px solid rgba(244,63,94,0.3)', color:'#fda4af', padding:'12px 16px', borderRadius:12, fontSize:13.5, marginBottom:22, display:'flex', alignItems:'center', gap:10 }}>
              <span style={{ width:7, height:7, borderRadius:'50%', background:'#f43f5e', flexShrink:0 }}/> {error}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            <div style={{ marginBottom:18 }}>
              <label style={{ display:'block', fontSize:11, fontWeight:700, color:'rgba(165,180,252,0.6)', marginBottom:9, letterSpacing:'1.2px', textTransform:'uppercase' }}>
                Email Address
              </label>
              <input className="li" type="email" value={email} onChange={e=>setEmail(e.target.value.toLowerCase())} placeholder="your@email.com" required
                style={{ width:'100%', padding:'14px 18px', background:'rgba(255,255,255,0.06)', border:'1.5px solid rgba(129,140,248,0.2)', borderRadius:13, fontSize:15.5, color:'#fff', fontFamily:'inherit', outline:'none', transition:'all .2s', boxSizing:'border-box' }} />
            </div>

            <div style={{ marginBottom:28 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:9 }}>
                <label style={{ fontSize:11, fontWeight:700, color:'rgba(165,180,252,0.6)', letterSpacing:'1.2px', textTransform:'uppercase' }}>
                  Password
                </label>
                <Link to="/forgot-password" style={{ fontSize:12, color:'#a5b4fc', textDecoration:'none', fontWeight:600, opacity:.85, transition:'opacity .2s' }}
                  onMouseEnter={e=>(e.currentTarget.style.opacity='1')} onMouseLeave={e=>(e.currentTarget.style.opacity='.85')}>
                  Forgot password?
                </Link>
              </div>
              <div style={{ position:'relative' }}>
                <input className="li" type={showPass?'text':'password'} value={password} onChange={e=>setPassword(e.target.value)} placeholder="••••••••" required
                  style={{ width:'100%', padding:'14px 60px 14px 18px', background:'rgba(255,255,255,0.06)', border:'1.5px solid rgba(129,140,248,0.2)', borderRadius:13, fontSize:15.5, color:'#fff', fontFamily:'inherit', outline:'none', transition:'all .2s', boxSizing:'border-box' }} />
                <button type="button" className="eye-btn" onClick={()=>setShowPass(v=>!v)}
                  style={{ position:'absolute', right:14, top:'50%', transform:'translateY(-50%)', background:'transparent', border:'none', color:'rgba(165,180,252,0.5)', cursor:'pointer', fontSize:12, fontWeight:600, padding:'4px 8px', borderRadius:6, fontFamily:'inherit', transition:'color .2s' }}>
                  {showPass?'Hide':'Show'}
                </button>
              </div>
            </div>

            <button type="submit" disabled={loading} className="lbtn"
              style={{ width:'100%', padding:'16px', background:'linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%)', color:'#ffffff', border:'none', borderRadius:13, fontSize:16, fontWeight:700, cursor:'pointer', fontFamily:'inherit', transition:'all .25s', boxShadow:'0 6px 24px rgba(99,102,241,0.4)', letterSpacing:'0.3px' }}>
              {loading ? 'Signing in…' : 'Sign In →'}
            </button>
          </form>

          <p style={{ textAlign:'center', fontSize:14, color:'rgba(165,180,252,0.4)', marginTop:22 }}>
            New student or staff?{' '}
            <Link to="/register" className="rlink" style={{ color:'#a5b4fc', fontWeight:700, textDecoration:'none', transition:'opacity .2s' }}>Create Account</Link>
          </p>
        </div>

        <p style={{ fontSize:10.5, color:'rgba(165,180,252,0.2)', marginTop:22, letterSpacing:'2px', textTransform:'uppercase', textAlign:'center' }}>
          BAUST · Library Management System
        </p>
      </div>
    </div>
  );
}
